(function(){const n={threshold:.1,rootMargin:"0px 0px -50px 0px"},s=new IntersectionObserver(function(t){t.forEach(function(e){e.isIntersecting&&(e.target.style.opacity="1",e.target.style.transform="translateY(0)")})},n);document.querySelectorAll(".fade-in-up").forEach(function(t){t.style.opacity="0",t.style.transform="translateY(30px)",t.style.transition="opacity 0.6s ease, transform 0.6s ease",s.observe(t)}),document.querySelectorAll('a[href^="#"]').forEach(function(t){t.addEventListener("click",function(e){const r=this.getAttribute("href");if(!r||r==="#")return;const o=document.querySelector(r);o&&(e.preventDefault(),o.scrollIntoView({behavior:"smooth",block:"start"}))})})})();
